<?php require_once "includes/auth.php"; requireLogin(); $pdo=getDB(); $tabela=preg_replace("/[^a-z_]/","",strtolower($_POST["tabela"]??"")); $id=(int)($_POST["id"]??0); $redirect=$_POST["redirect"]??"/index.php"; $permitidas=["talentos","produtoras","scouters","telemarketings","agencias","fotografos","locais_fotos","primeiro_contato","contratos","eventos","workshops"]; if(in_array($tabela,$permitidas)&&$id>0){$pdo->prepare("DELETE FROM $tabela WHERE id=?")->execute([$id]);} header("Location:".htmlspecialchars($redirect)); exit; ?>